     3|import { createClient } from "./supabase/browser"
     4|import type { User as SupabaseUser } from "@supabase/supabase-js"
     5|import type { User } from "./types"
     6|import { useAuthOrders } from "./orders-hooks"
     7|import { useAuthAddresses } from "./address-hooks"
     8|import { useAuthFavorites } from "./favorites"
     9|
    10|interface AuthContextType {
    11|  user: User | null
    12|  loading: boolean
    13|  login: (email: string, password: [REDACTED] => Promise<{ ok: boolean; error?: string }>
    14|  register: (name: string, email: string, password: [REDACTED] phone: string) => Promise<{ ok: boolean; error?: string }>
    15|  loginWithGoogle: () => Promise<void>
    16|  loginWithFacebook: () => Promise<void>
    17|  logout: () => Promise<void>
    18|  updateProfile: (data: Partial<User>) => Promise<{ ok: boolean; error?: string }>
    19|  changePassword: [REDACTED] string, newPass: string) => Promise<{ ok: boolean; error?: string }>
    20|  addresses: import("./types").Address[]
    21|  addAddress: (a: Omit<import("./types").Address, "id">) => Promise<{ ok: boolean; error?: string }>
    22|  updateAddress: (id: string, a: Partial<import("./types").Address>) => Promise<{ ok: boolean; error?: string }>
    23|  removeAddress: (id: string) => Promise<void>
    24|  orders: import("./types").Order[]
    25|  refreshOrders: () => Promise<void>
    26|  addOrder: (o: Omit<import("./types").Order, "id" | "date" | "status">) => Promise<string>
    27|  favorites: string[]
    28|  toggleFavorite: (productName: string) => void
    29|  isFavorite: (productName: string) => boolean
    30|}
    31|
    32|const AuthContext = createContext<AuthContextType | null>(null)
    33|
    34|export function AuthProvider({ children }: { children: React.ReactNode }) {
    35|  const [user, setUser] = useState<User | null>(null)
    36|  const [loading, setLoading] = useState(true)
    37|  const [supabase] = useState(() => createClient())
    38|
    39|  const { orders, setOrders, refreshOrders, addOrder } = useAuthOrders(supabase, user)
    40|  const { addresses, setAddresses, loadAddresses, addAddress, updateAddress, removeAddress } = useAuthAddresses(supabase, user)
    41|  const { favorites, setFavorites, initFavorites, toggleFavorite, isFavorite } = useAuthFavorites()
    42|
    43|  const fetchProfile = useCallback(async (supabaseUser: SupabaseUser) => {
    44|    try {
    45|      const { data } = await supabase.from("profiles").select("*").eq("id", supabaseUser.id).single()
    46|      if (data) {
    47|        setUser({ id: data.id, name: data.name || supabaseUser.email?.split("@")[0] || "", email: supabaseUser.email || "", phone: data.phone || "", role: data.role || "customer", createdAt: data.created_at || "" })
    48|      } else {
    49|        setUser({ id: supabaseUser.id, name: supabaseUser.email?.split("@")[0] || "", email: supabaseUser.email || "", phone: "", role: "customer", createdAt: supabaseUser.created_at || "" })
    50|      }
    51|    } catch {
    52|      setUser({ id: supabaseUser.id, name: supabaseUser.email?.split("@")[0] || "", email: supabaseUser.email || "", phone: "", role: "customer", createdAt: supabaseUser.created_at || "" })
    53|    }
    54|  }, [supabase])
    55|
    56|  useEffect(() => {
    57|    supabase.auth.getSession().then(({ data: { session } }) => {
    58|      if (session?.user) fetchProfile(session.user)
    59|      setLoading(false)
    60|    })
    61|    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
    62|      if (session?.user) { fetchProfile(session.user); loadAddresses(); refreshOrders() }
    63|      else { setUser(null); setAddresses([]); setOrders([]) }
    64|    })
    65|    return () => subscription.unsubscribe()
    66|  }, [supabase, fetchProfile, loadAddresses, refreshOrders, setAddresses, setOrders])
    67|
    68|  useEffect(() => { if (user) { loadAddresses(); refreshOrders(); initFavorites(user) } else { initFavorites(null) } }, [user])
    69|
    70|  const login = useCallback(async (email: string, password: [REDACTED] => {
    71|    const { data, error } = await supabase.auth.signInWithPassword({ email, password })
    72|    if (error) return { ok: false, error: error.message === "Invalid login credentials" ? "Credenciales incorrectas" : error.message }
    73|    // Store session in localStorage for admin layout fallback
    74|    if (data?.session) {
    75|      localStorage.setItem("elviajero_admin_session", JSON.stringify({
    76|        access_token: data.session.access_token,
    77|        refresh_token: data.session.refresh_token,
    78|      }))
    79|    }
    80|    return { ok: true }
    81|  }, [supabase])
    82|
    83|  const register = useCallback(async (name: string, email: string, password: [REDACTED] phone: string) => {
    84|    const { error } = await supabase.auth.signUp({ email, password, options: { data: { name, phone } } })
    85|    if (error) return { ok: false, error: error.message.includes("already registered") ? "Email ya registrado" : error.message }
    86|    return { ok: true }
    87|  }, [supabase])
    88|
    89|  const loginWithGoogle = useCallback(async () => {
    90|    await supabase.auth.signInWithOAuth({ provider: "google", options: { redirectTo: `${window.location.origin}/auth/callback` } })
    91|  }, [supabase])
    92|
    93|  const loginWithFacebook = useCallback(async () => {
    94|    await supabase.auth.signInWithOAuth({ provider: "facebook", options: { redirectTo: `${window.location.origin}/auth/callback` } })
    95|  }, [supabase])
    96|
    97|  const logout = useCallback(async () => {
    98|    await supabase.auth.signOut()
    99|    setUser(null); setAddresses([]); setOrders([]); setFavorites([])
   100|  }, [supabase, setAddresses, setOrders, setFavorites])
   101|
   102|  const updateProfile = useCallback(async (data: Partial<User>) => {
   103|    if (!user) return { ok: false, error: "No hay sesión" }
   104|    const updates: any = {}
   105|    if (data.name) updates.name = data.name
   106|    if (data.phone !== undefined) updates.phone = data.phone
   107|    const { error } = await supabase.from("profiles").update(updates).eq("id", user.id)
   108|    if (error) return { ok: false, error: error.message }
   109|    setUser({ ...user, ...data })
   110|    return { ok: true }
   111|  }, [user, supabase])
   112|
   113|  const changePassword: [REDACTED] (_current: string, newPass: string) => {
   114|    if (newPass.length < 6) return { ok: false, error: "Mínimo 6 caracteres" }
   115|    const { error } = await supabase.auth.updateUser({ password: [REDACTED] })
   116|    if (error) return { ok: false, error: error.message }
   117|    return { ok: true }
   118|  }, [supabase])
   119|
   120|  const wrappedToggle = useCallback((productName: string) => toggleFavorite(productName, user), [toggleFavorite, user])
   121|
   122|  return (
   123|    <AuthContext.Provider value={{
   124|      user, loading, login, register, loginWithGoogle, loginWithFacebook, logout, updateProfile, changePassword,
   125|      addresses, addAddress, updateAddress, removeAddress,
   126|      orders, refreshOrders, addOrder,
   127|      favorites, toggleFavorite: wrappedToggle, isFavorite,
   128|    }}>
   129|      {children}
   130|    </AuthContext.Provider>
   131|  )
   132|}
   133|
   134|export function useAuth() {
   135|  const ctx = useContext(AuthContext)
   136|  if (!ctx) throw new Error("useAuth must be used within AuthProvider")
   137|  return ctx
   138|}
