  "privacy-accordion": PrivacyAccordion,
  "legal-content": PrivacyAccordion,
}

// ═══════════════════════════════════════════════════════════════════════════════
// SECTION RENDERER
// The main component that renders all sections for a page.
// ═══════════════════════════════════════════════════════════════════════════════

export interface SectionsRendererProps {
  /** The page sections config array */
  sections?: PageSection[]
  /** The full page config (also accepts sections.sections if sections param omitted) */
  pageConfig?: PageConfig & { sections?: PageSection[] }
  /** The full content JSON (for resolveContent) */
  content?: Record<string, any>
  /** Image manifest for @img: resolver */
  images?: Record<string, { src: string; alt?: string }>
  /** Current locale */
  locale?: string
  /** Optional override for the section registry */
  sections?: PageSection[]
  /** Optional extra section registry to merge with defaults */
  extraSections?: SectionRegistry
  /** Header component to render at the top (optional — use if you want a default header) */
  header?: React.ComponentType<{ content: any; locale?: string }>
  /** Footer component to render at the bottom (optional) */
  footer?: React.ComponentType<{ content: any; locale?: string }>
}

export function SectionsRenderer(props: SectionsRendererProps): JSX.Element {
  const {
    pageConfig,
    content: contentData,
    images,
    locale,
    extraSections,
  } = props

  // Determine section list
  const sectionList = pageConfig?.sections || []

  // Merge section registries
  const registry: SectionRegistry = {
    ...DEFAULT_SECTIONS,
    ...extraSections,
  }

  if (!sectionList.length) {
    return <GenericSection data={pageConfig || contentData} />
  }

  return (
    <>
      {sectionList
        .filter((section) => isSectionEnabled(section.enabledWhen, contentData))
        .map((section, index) => {
          const SectionComponent = registry[section.id] || GenericSection
          const data = section.content ? resolveContent(contentData, section.content) : undefined

          return (
            <SectionComponent
              key={`section-${section.id}-${index}`}
              variant={section.variant}
              pageContent={data || contentData}
              data={data}
              images={images}
              locale={locale}
            />
          )
        })}
    </>
  )
}

/** Create an extended SectionsRenderer with additional section types */
export function createSectionsRenderer(extraSections: SectionRegistry) {
  return (props: SectionsRendererProps) => (
    <SectionsRenderer {...props} extraSections={{ ...extraSections }} />
  )
}
